package main

import (
    "fmt"
    "sync"
    "time"
)

// ---- Race condition example ----
func main() {
    // ---- Race condition ----
    fmt.Println("=== Race Condition ===")

    counter := 0
    var wg sync.WaitGroup

    for i := 0; i < 1000; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            counter++  // Race condition!
        }()
    }

    wg.Wait()
    fmt.Printf("Counter: %d\n", counter)

    // ---- Fixed with mutex ----
    fmt.Println("\n=== Fixed with Mutex ===")

    var mu sync.Mutex
    safeCounter := 0

    for i := 0; i < 1000; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            mu.Lock()
            safeCounter++
            mu.Unlock()
        }()
    }

    wg.Wait()
    fmt.Printf("Safe counter: %d\n", safeCounter)

    // ---- Race condition with maps ----
    fmt.Println("\n=== Race Condition with Maps ===")

    m := make(map[string]int)

    for i := 0; i < 10; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            m["key"]++  // Race condition!
        }()
    }

    wg.Wait()
    fmt.Printf("Map value: %d\n", m["key"])

    // ---- Fixed with sync.Map ----
    fmt.Println("\n=== Fixed with sync.Map ===")

    var syncMap sync.Map

    for i := 0; i < 10; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            val, _ := syncMap.LoadOrStore("key", 0)
            syncMap.Store("key", val.(int)+1)
        }()
    }

    wg.Wait()
    value, _ := syncMap.Load("key")
    fmt.Printf("sync.Map value: %d\n", value)
}

